parameters.jsCode:
let rawOutput = $input.first().json.output;
// Strip markdown formatting if the LLM adds it
rawOutput = rawOutput.replace(/```json\n?/g, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(rawOutput);
} catch (error) {
  throw new Error(`Invalid JSON returned from AI: ${rawOutput}`);
}

return [{ json: parsed }];

