parameters.jsCode:
// Current deal
const currentDeal = $("Fetch Deal Details").first().json;

// Historical deals
const historicalDeals = $("Fetch Historical Won Deals").all().map(item => item.json);

// Activities
const activities = $("Deal Task History").all().map(item => item.json);

// --------------------
// Feature Engineering
// --------------------

// Days open 
const createdDate = new Date(currentDeal.CreatedDate);
const today = new Date();

const daysOpen = Math.max(
  1,
  Math.ceil((today - createdDate) / (1000 * 60 * 60 * 24))
);

// Deal velocity
const dealVelocity = (currentDeal.Amount || 0) / daysOpen;

// Activity score
const activityScore = activities.length;

// Engagement level
let engagementLevel = "Low";
if (activityScore > 10) engagementLevel = "High";
else if (activityScore > 5) engagementLevel = "Medium";

// Stage weight (ML-style encoding)
const stageWeights = {
  "Prospecting": 1,
  "Qualification": 2,
  "Proposal/Price Quote": 3,
  "Negotiation/Review": 4,
  "Closed Won": 5
};

const stageWeight = stageWeights[currentDeal.StageName] || 1;

// Time pressure (days left)
let timePressure = 0;
if (currentDeal.CloseDate) {
  const closeDate = new Date(currentDeal.CloseDate);
  timePressure = Math.floor((closeDate - today) / (1000 * 60 * 60 * 24));
}

// --------------------
// Historical calculations
// --------------------
const totalDeals = historicalDeals.length;

const wonDeals = historicalDeals.filter(d => d.IsWon === true).length;

const totalAmount = historicalDeals.reduce((sum, d) => {
  return sum + (d.Amount || 0);
}, 0);

const avgHistoricalAmount =
  totalDeals > 0 ? totalAmount / totalDeals : 0;

const historicalWinRate =
  totalDeals > 0 ? (wonDeals / totalDeals) * 100 : 0;

const amountDeviation =
  (currentDeal.Amount || 0) - avgHistoricalAmount;

// --------------------
// Risk scoring (IMPROVED)
// --------------------
let riskScore = 0;

// Probability-based risk
if ((currentDeal.Probability || 0) < 50) riskScore += 30;
else if ((currentDeal.Probability || 0) < 70) riskScore += 15;

// Amount deviation risk
if (amountDeviation < -50000) riskScore += 20;

// Stage risk
if (currentDeal.StageName === "Prospecting") riskScore += 25;
if (currentDeal.StageName === "Qualification") riskScore += 15;
if (currentDeal.StageName === "Negotiation/Review") riskScore += 10;

// Historical win-rate risk
if (historicalWinRate < 70) riskScore += 20;

// Activity-based risk 
if (activityScore === 0) riskScore += 30;
else if (activityScore < 3) riskScore += 20;
else if (activityScore < 6) riskScore += 10;

// Time pressure risk
if (timePressure < 5) riskScore += 10;

// Deal aging risk (
if (daysOpen > 30) riskScore += 10;

// Cap at 100
riskScore = Math.min(riskScore, 100);

// Risk label
let riskLabel = "Low";
if (riskScore >= 70) riskLabel = "High";
else if (riskScore >= 40) riskLabel = "Medium";

// --------------------
// Final output
// --------------------
return [
  {
    json: {
      ...currentDeal,

      // Historical
      totalHistoricalDeals: totalDeals,
      wonHistoricalDeals: wonDeals,
      avgHistoricalAmount,
      historicalWinRate,
      amountDeviation,

      // Feature Engineering
      daysOpen,
      dealVelocity,
      activityScore,
      engagementLevel,
      stageWeight,
      timePressure,

      // Risk
      riskScore,
      riskLabel
    }
  }
];
